#include <bits/stdc++.h>
using namespace std;

const int N=10010,M=100*N,INF=1e9;

int n,m,S,T,dr[4]={2,3,0,1};
vector<int> a[N];
int head[N],ver[M],edge[M],val[M],nxt[M],tot=1;
int dis[N],f[N],pre[N],q[M],ans,cnt;
bool inq[N];

int cal(int x,int y,int tp){
    return 4*(x-1)*m+4*(y-1)+tp+1;
}

void add(int x,int y,int a,int b){
	if(x==S || y==T) cnt+=a;
    ver[++tot]=y,edge[tot]=a,val[tot]=b,nxt[tot]=head[x],head[x]=tot;
    ver[++tot]=x,edge[tot]=0,val[tot]=-b,nxt[tot]=head[y],head[y]=tot;
}

bool bfs(){
    memset(dis,0x3f,sizeof(dis));
    memset(inq,0,sizeof(inq));
    int hh=1,tt=0;
    dis[S]=0,f[S]=INF;
    q[++tt]=S,inq[S]=1;
    while(hh<=tt){
        int x=q[hh++];
        inq[x]=0;
        for(int i=head[x],y;i;i=nxt[i])
            if(edge[i] && dis[y=ver[i]]>dis[x]+val[i]){
                dis[y]=dis[x]+val[i],f[y]=min(edge[i],f[x]);
                pre[y]=i;
                if(!inq[y]) q[++tt]=y,inq[y]=1;
            }
    }
    return dis[T]<INF;
}

void Update(){
    int p=T,flow=f[T];
    ans+=f[T]*dis[T],cnt-=2*f[T];
    while(p!=S){
        int i=pre[p];
        edge[i]-=flow,edge[i^1]+=flow;
        p=ver[i^1];
    }
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++){
        a[i].push_back(0);
        for(int j=1,x;j<=m;j++){
            scanf("%d",&x);
            a[i].push_back(x);
        }
    }
    S=4*n*m+1,T=4*n*m+2;
    for(int i=1;i<=n;i++)
        for(int j=1;j<=m;j++){
            if((i+j)%2==0){
                if(i>1) add(cal(i,j,0),cal(i-1,j,2),1,0);
                if(i<n) add(cal(i,j,2),cal(i+1,j,0),1,0);
                if(j>1) add(cal(i,j,3),cal(i,j-1,1),1,0);
                if(j<m) add(cal(i,j,1),cal(i,j+1,3),1,0);
            }
            int cnt=0;
            for(int k=0;k<4;k++)
                if((a[i][j]>>k)&1){
                    if((i+j)%2==0) add(S,cal(i,j,k),1,0);
                    else add(cal(i,j,k),T,1,0);
                    cnt++;
                }
            if(cnt==0 || cnt==4) continue;
            if(cnt==1){
                int p;
                for(int k=0;k<4;k++) if((a[i][j]>>k)&1) p=k;
                for(int k=0;k<4;k++)
                    if(p!=k){
                        if((i+j)%2==0) add(cal(i,j,p),cal(i,j,k),1,min((p-k+4)%4,(k-p+4)%4));
                        else add(cal(i,j,k),cal(i,j,p),1,min((p-k+4)%4,(k-p+4)%4));
                    }
            }else if(cnt==2){
            	bool flag=false;
				for(int k=0;k<4;k++) if(((a[i][j]>>k)&1) && ((a[i][j]>>dr[k])&1)) flag=true;
				if(flag) continue;
				for(int k=0;k<4;k++)
					if((a[i][j]>>k)&1){
						if((i+j)%2==0) add(cal(i,j,k),cal(i,j,dr[k]),1,1);
						else add(cal(i,j,dr[k]),cal(i,j,k),1,1);
					}
			}else{
                int p;
                for(int k=0;k<4;k++) if(!((a[i][j]>>k)&1)) p=k;
                for(int k=0;k<4;k++){
                    if(k==(p+2)%4){
                        if((i+j)%2==0) add(cal(i,j,k),cal(i,j,p),1,2);
                        else add(cal(i,j,p),cal(i,j,k),1,2);
                    }else if(k!=p){
                        if((i+j)%2==0) add(cal(i,j,k),cal(i,j,p),1,1);
                        else add(cal(i,j,p),cal(i,j,k),1,1);
                    }
                }
            }
        }
    while(bfs())
        Update();
    if(cnt)
    	printf("-1");
    else
    	printf("%d",ans);
    return 0;
}
